import { tool } from "@opencode-ai/plugin"
import {
  defaultArtifactPath,
  getTicket,
  getTicketWorkflowState,
  loadArtifactRegistry,
  loadManifest,
  loadWorkflowState,
  normalizeRepoPath,
  registerArtifactSnapshot,
  releaseLaneLease,
  saveWorkflowBundle,
  setPlanApprovedForTicket,
  syncWorkflowSelection,
  type Artifact,
  type Ticket,
  type TicketSourceMode,
  writeText,
} from "../lib/workflow"

function normalizeOptional(value: string | undefined): string | undefined {
  if (typeof value !== "string") return undefined
  const normalized = value.trim()
  return normalized || undefined
}

function isCompletedHistoricalTicket(ticket: Ticket): boolean {
  return ticket.status === "done" || ticket.resolution_state === "done" || ticket.resolution_state === "superseded"
}

function findEvidenceArtifact(sourceTicket: Ticket, targetTicket: Ticket, artifactPath: string): Artifact | undefined {
  const normalized = normalizeRepoPath(artifactPath)
  return [...sourceTicket.artifacts, ...targetTicket.artifacts].find(
    (artifact) => artifact.path === normalized && artifact.trust_state === "current",
  )
}

function renderArtifact(args: {
  sourceTicketId: string
  targetTicketId: string
  evidenceArtifactPath: string
  reason: string
  replacementSourceTicketId: string
  replacementSourceMode: TicketSourceMode | null
  removedDependencyOnSource: boolean
  supersededTarget: boolean
}): string {
  return `# Ticket Reconciliation

## Canonical Source

- source_ticket_id: ${args.sourceTicketId}
- target_ticket_id: ${args.targetTicketId}
- replacement_source_ticket_id: ${args.replacementSourceTicketId}
- replacement_source_mode: ${args.replacementSourceMode || "unchanged"}

## Evidence

- evidence_artifact_path: ${args.evidenceArtifactPath}

## Applied Reconciliation

- removed_dependency_on_source: ${args.removedDependencyOnSource ? "true" : "false"}
- superseded_target: ${args.supersededTarget ? "true" : "false"}

## Reason

${args.reason}
`
}

export default tool({
  description: "Reconcile stale or contradictory source/follow-up linkage using current registered evidence instead of manual manifest edits.",
  args: {
    source_ticket_id: tool.schema.string().describe("Canonical source ticket that should own the follow-up linkage."),
    target_ticket_id: tool.schema.string().describe("Follow-up ticket whose lineage or dependency graph needs reconciliation."),
    evidence_artifact_path: tool.schema.string().describe("Current registered artifact path that justifies the reconciliation."),
    reason: tool.schema.string().describe("Why the current ticket graph is stale or contradictory."),
    replacement_source_ticket_id: tool.schema.string().describe("Optional replacement source ticket. Defaults to source_ticket_id.").optional(),
    replacement_source_mode: tool.schema.enum(["process_verification", "post_completion_issue", "net_new_scope", "split_scope"]).describe("Optional replacement source mode for the target ticket.").optional(),
    remove_dependency_on_source: tool.schema.boolean().describe("Whether to remove any target dependency on the canonical source ticket.").optional(),
    supersede_target: tool.schema.boolean().describe("Whether to close the target ticket as superseded after reconciliation.").optional(),
    activate_source: tool.schema.boolean().describe("Whether to make the canonical source ticket active after reconciliation.").optional(),
  },
  async execute(args) {
    const manifest = await loadManifest()
    const workflow = await loadWorkflowState()
    const sourceTicket = getTicket(manifest, args.source_ticket_id)
    const targetTicket = getTicket(manifest, args.target_ticket_id)
    const replacementSourceTicketId = normalizeOptional(args.replacement_source_ticket_id) || sourceTicket.id
    const replacementSourceTicket = getTicket(manifest, replacementSourceTicketId)
    const evidenceArtifactPath = normalizeRepoPath(args.evidence_artifact_path)
    const reason = args.reason.trim()
    const replacementSourceMode = args.replacement_source_mode || targetTicket.source_mode || null
    const removeDependencyOnSource = args.remove_dependency_on_source !== false
    const supersedeTarget = args.supersede_target === true

    if (!reason) {
      throw new Error("reason must not be empty.")
    }

    const evidenceArtifact = findEvidenceArtifact(sourceTicket, targetTicket, evidenceArtifactPath)
    if (!evidenceArtifact) {
      throw new Error(`Neither ${sourceTicket.id} nor ${targetTicket.id} has a current evidence artifact at ${evidenceArtifactPath}.`)
    }

    if (replacementSourceMode === "split_scope" && (!["open", "reopened"].includes(replacementSourceTicket.resolution_state) || replacementSourceTicket.status === "done")) {
      throw new Error(`split_scope reconciliation requires an open or reopened replacement source ticket. ${replacementSourceTicket.id} is not currently eligible.`)
    }
    if (replacementSourceMode === "post_completion_issue" && !isCompletedHistoricalTicket(replacementSourceTicket)) {
      throw new Error(`post_completion_issue reconciliation requires a completed historical source ticket. ${replacementSourceTicket.id} is still open.`)
    }
    if (replacementSourceMode === "process_verification" && !isCompletedHistoricalTicket(replacementSourceTicket)) {
      throw new Error(`process_verification reconciliation requires a completed historical source ticket. ${replacementSourceTicket.id} is still open.`)
    }

    const previousSourceTicketId = normalizeOptional(targetTicket.source_ticket_id)
    if (previousSourceTicketId) {
      const previousSource = manifest.tickets.find((ticket) => ticket.id === previousSourceTicketId)
      if (previousSource) {
        previousSource.follow_up_ticket_ids = previousSource.follow_up_ticket_ids.filter((candidate) => candidate !== targetTicket.id)
      }
    }

    targetTicket.source_ticket_id = replacementSourceTicket.id
    targetTicket.source_mode = replacementSourceMode ?? undefined

    if (!replacementSourceTicket.follow_up_ticket_ids.includes(targetTicket.id)) {
      replacementSourceTicket.follow_up_ticket_ids.push(targetTicket.id)
    }

    if (removeDependencyOnSource) {
      const contradictorySourceIds = new Set([sourceTicket.id, replacementSourceTicket.id, previousSourceTicketId].filter(Boolean))
      targetTicket.depends_on = targetTicket.depends_on.filter((candidate) => !contradictorySourceIds.has(candidate))
    }

    if (supersedeTarget) {
      targetTicket.stage = "closeout"
      targetTicket.status = "done"
      targetTicket.resolution_state = "superseded"
      targetTicket.verification_state = "invalidated"
      getTicketWorkflowState(workflow, targetTicket.id).needs_reverification = false
      releaseLaneLease(workflow, targetTicket.id)
      setPlanApprovedForTicket(workflow, targetTicket.id, false)
      if (manifest.active_ticket === targetTicket.id) {
        manifest.active_ticket = replacementSourceTicket.id
      }
    }

    if (args.activate_source === true) {
      manifest.active_ticket = replacementSourceTicket.id
    }
    syncWorkflowSelection(workflow, manifest)

    const registry = await loadArtifactRegistry()
    const canonicalPath = normalizeRepoPath(defaultArtifactPath(sourceTicket.id, "review", "ticket-reconciliation"))
    await writeText(
      canonicalPath,
      renderArtifact({
        sourceTicketId: sourceTicket.id,
        targetTicketId: targetTicket.id,
        evidenceArtifactPath,
        reason,
        replacementSourceTicketId: replacementSourceTicket.id,
        replacementSourceMode,
        removedDependencyOnSource: removeDependencyOnSource,
        supersededTarget,
      }),
    )
    const reconciliationArtifact = await registerArtifactSnapshot({
      ticket: sourceTicket,
      registry,
      source_path: canonicalPath,
      kind: "ticket-reconciliation",
      stage: "review",
      summary: `Reconciled ${targetTicket.id} against ${replacementSourceTicket.id}.`,
    })

    await saveWorkflowBundle({ workflow, manifest, registry })

    return JSON.stringify(
      {
        source_ticket_id: sourceTicket.id,
        target_ticket_id: targetTicket.id,
        replacement_source_ticket_id: replacementSourceTicket.id,
        replacement_source_mode: replacementSourceMode,
        removed_dependency_on_source: removeDependencyOnSource,
        superseded_target: supersedeTarget,
        evidence_artifact_path: evidenceArtifact.path,
        reconciliation_artifact: reconciliationArtifact.path,
        active_ticket: manifest.active_ticket,
      },
      null,
      2,
    )
  },
})

import { tool } from "@opencode-ai/plugin"
import {
  createTicketRecord,
  getTicket,
  loadManifest,
  loadWorkflowState,
  saveWorkflowBundle,
  setPlanApprovedForTicket,
  syncWorkflowSelection,
  ticketFilePath,
  type TicketSourceMode,
} from "../lib/workflow"

function normalizeOptional(value: string | undefined): string | undefined {
  if (typeof value !== "string") return undefined
  const normalized = value.trim()
  return normalized || undefined
}

export default tool({
  description: "Create a new ticket or linked follow-up ticket, including process-verification, post-completion issue, and open-parent split follow-up tickets.",
  args: {
    id: tool.schema.string().describe("New ticket id."),
    title: tool.schema.string().describe("New ticket title."),
    lane: tool.schema.string().describe("Owning lane or project area."),
    wave: tool.schema.number().int().describe("Execution wave number."),
    summary: tool.schema.string().describe("Ticket summary."),
    acceptance: tool.schema.array(tool.schema.string()).describe("Acceptance criteria list."),
    depends_on: tool.schema.array(tool.schema.string()).describe("Dependency ticket ids.").optional(),
    decision_blockers: tool.schema.array(tool.schema.string()).describe("Unresolved blockers for this ticket.").optional(),
    parallel_safe: tool.schema.boolean().describe("Whether the ticket can be advanced in a parallel lane when dependencies are satisfied.").optional(),
    overlap_risk: tool.schema.enum(["low", "medium", "high"]).describe("Expected overlap risk with other tickets.").optional(),
    source_ticket_id: tool.schema.string().describe("Optional source ticket that this ticket extends or remediates.").optional(),
    source_mode: tool.schema.enum(["process_verification", "post_completion_issue", "net_new_scope", "split_scope"]).describe("Why this ticket is being created.").optional(),
    evidence_artifact_path: tool.schema.string().describe("Optional registered artifact path that justifies creation of this linked ticket.").optional(),
    activate: tool.schema.boolean().describe("Whether to make the new ticket active immediately.").optional(),
  },
  async execute(args) {
    const manifest = await loadManifest()
    const workflow = await loadWorkflowState()
    const sourceMode: TicketSourceMode = args.source_mode || "net_new_scope"
    const sourceTicketId = normalizeOptional(args.source_ticket_id)
    const evidenceArtifactPath = normalizeOptional(args.evidence_artifact_path)

    if (manifest.tickets.some((ticket) => ticket.id === args.id.trim())) {
      throw new Error(`Ticket already exists: ${args.id.trim()}`)
    }

    const ticket = createTicketRecord({
      id: args.id,
      title: args.title,
      lane: args.lane,
      wave: args.wave,
      summary: args.summary,
      acceptance: args.acceptance,
      depends_on: args.depends_on,
      decision_blockers: args.decision_blockers,
      parallel_safe: args.parallel_safe,
      overlap_risk: args.overlap_risk,
      source_ticket_id: sourceTicketId,
      source_mode: sourceMode,
    })

    for (const dependency of ticket.depends_on) {
      getTicket(manifest, dependency)
    }

    let sourceTicket = undefined as ReturnType<typeof getTicket> | undefined
    if (sourceMode !== "net_new_scope") {
      if (!sourceTicketId) {
        throw new Error(`source_ticket_id is required when source_mode is ${sourceMode}.`)
      }
      sourceTicket = getTicket(manifest, sourceTicketId)

      if (ticket.depends_on.includes(sourceTicket.id)) {
        throw new Error(`Ticket ${ticket.id} cannot depend on its source ticket ${sourceTicket.id}; reconcile lineage or split scope instead of creating a contradictory dependency.`)
      }

      if (sourceMode === "process_verification") {
        if (!workflow.pending_process_verification) {
          throw new Error("process_verification ticket creation is only available while pending_process_verification is true.")
        }
        if (sourceTicket.status !== "done") {
          throw new Error(`Source ticket ${sourceTicket.id} must be done before creating a process-verification follow-up ticket.`)
        }
        if (!evidenceArtifactPath) {
          throw new Error("evidence_artifact_path is required for process_verification ticket creation.")
        }
        const verificationArtifact = sourceTicket.artifacts.find(
          (artifact) =>
            artifact.path === evidenceArtifactPath &&
            artifact.stage === "review" &&
            artifact.kind === "backlog-verification" &&
            artifact.trust_state === "current",
        )
        if (!verificationArtifact) {
          throw new Error(
            `Source ticket ${sourceTicket.id} does not have a current review/backlog-verification artifact at ${evidenceArtifactPath}.`,
          )
        }
      }

      if (sourceMode === "post_completion_issue") {
        if (sourceTicket.status !== "done" && !["done", "superseded"].includes(sourceTicket.resolution_state)) {
          throw new Error(`Source ticket ${sourceTicket.id} must already represent completed historical scope before creating a post-completion issue ticket.`)
        }
        if (!evidenceArtifactPath) {
          throw new Error("evidence_artifact_path is required for post_completion_issue ticket creation.")
        }
        const evidenceArtifact = sourceTicket.artifacts.find((artifact) => artifact.path === evidenceArtifactPath)
        if (!evidenceArtifact) {
          throw new Error(`Source ticket ${sourceTicket.id} does not reference the evidence artifact ${evidenceArtifactPath}.`)
        }
      }

      if (sourceMode === "split_scope") {
        if (!["open", "reopened"].includes(sourceTicket.resolution_state) || sourceTicket.status === "done") {
          throw new Error(`Source ticket ${sourceTicket.id} must remain open or reopened before creating a split-scope child ticket.`)
        }
      }
    }

    manifest.tickets.push(ticket)
    if (sourceTicket && !sourceTicket.follow_up_ticket_ids.includes(ticket.id)) {
      sourceTicket.follow_up_ticket_ids.push(ticket.id)
    }
    if (sourceTicket && sourceMode === "split_scope") {
      const splitNote = `Split scope delegated to follow-up ticket ${ticket.id}. Keep the parent open and non-foreground until the child work lands.`
      if (!sourceTicket.decision_blockers.includes(splitNote)) {
        sourceTicket.decision_blockers.push(splitNote)
      }
    }

    setPlanApprovedForTicket(workflow, ticket.id, false)
    const activateNewTicket = typeof args.activate === "boolean"
      ? args.activate
      : sourceMode === "split_scope" && sourceTicket?.id === manifest.active_ticket
    if (activateNewTicket) {
      manifest.active_ticket = ticket.id
    }
    syncWorkflowSelection(workflow, manifest)

    await saveWorkflowBundle({ workflow, manifest })

    return JSON.stringify(
      {
        created_ticket: ticket.id,
        path: ticketFilePath(ticket.id),
        status: ticket.status,
        source_ticket_id: sourceTicket?.id || null,
        source_mode: sourceMode,
        evidence_artifact_path: evidenceArtifactPath || null,
        activated: activateNewTicket,
      },
      null,
      2,
    )
  },
})

import { tool } from "@opencode-ai/plugin"
import {
  createTicketRecord,
  defaultArtifactPath,
  getTicket,
  getTicketWorkflowState,
  loadArtifactRegistry,
  loadManifest,
  loadWorkflowState,
  markArtifactsHistorical,
  markTicketReopened,
  normalizeRepoPath,
  registerArtifactSnapshot,
  resolveDefectOutcome,
  saveWorkflowBundle,
  setPlanApprovedForTicket,
  syncWorkflowSelection,
  type DefectOutcome,
  writeText,
} from "../lib/workflow"

function normalizeOptional(value: string | undefined): string | undefined {
  if (typeof value !== "string") return undefined
  const normalized = value.trim()
  return normalized || undefined
}

function renderArtifact(args: {
  sourceTicketId: string
  defectClass: string
  evidenceArtifactPath: string
  outcome: DefectOutcome
  priorCompletionTrusted: boolean
  requiredNextAction: string
}): string {
  return `# Issue Discovery

## Source Ticket

- ${args.sourceTicketId}

## Defect

- defect_class: ${args.defectClass}
- evidence_artifact_path: ${args.evidenceArtifactPath}

## Trust

- prior_completion_trusted: ${args.priorCompletionTrusted ? "true" : "false"}
- required_next_action: ${args.requiredNextAction}
- outcome: ${args.outcome}
`
}

export default tool({
  description: "Record a post-completion defect and deterministically route it to no-action, reopen, follow-up, or rollback-required handling.",
  args: {
    source_ticket_id: tool.schema.string().describe("Completed ticket where the issue was discovered."),
    defect_class: tool.schema.string().describe("Short defect classification, for example regression, scope-gap, or environment drift."),
    acceptance_broken: tool.schema.boolean().describe("Whether the original accepted scope is now false."),
    scope_changed: tool.schema.boolean().describe("Whether the newly discovered issue expands scope beyond the original ticket."),
    rollback_required: tool.schema.boolean().describe("Whether the issue requires rollback or containment work before normal forward progress."),
    evidence_artifact_path: tool.schema.string().describe("Registered artifact path that demonstrates the issue."),
    follow_up_id: tool.schema.string().describe("New ticket id for follow-up or rollback work. Required when the intake creates a new ticket.").optional(),
    follow_up_title: tool.schema.string().describe("Title for the follow-up or rollback ticket.").optional(),
    follow_up_lane: tool.schema.string().describe("Lane for the follow-up or rollback ticket.").optional(),
    follow_up_wave: tool.schema.number().int().describe("Wave number for the follow-up or rollback ticket.").optional(),
    follow_up_summary: tool.schema.string().describe("Summary for the follow-up or rollback ticket.").optional(),
    follow_up_acceptance: tool.schema.array(tool.schema.string()).describe("Acceptance criteria for the follow-up or rollback ticket.").optional(),
    follow_up_depends_on: tool.schema.array(tool.schema.string()).describe("Dependency ticket ids for the follow-up or rollback ticket.").optional(),
    follow_up_decision_blockers: tool.schema.array(tool.schema.string()).describe("Optional blockers for the follow-up or rollback ticket.").optional(),
    follow_up_parallel_safe: tool.schema.boolean().describe("Whether the follow-up ticket is safe for a parallel lane.").optional(),
    follow_up_overlap_risk: tool.schema.enum(["low", "medium", "high"]).describe("Expected overlap risk for the follow-up ticket.").optional(),
  },
  async execute(args) {
    const manifest = await loadManifest()
    const workflow = await loadWorkflowState()
    const sourceTicket = getTicket(manifest, args.source_ticket_id)
    const evidenceArtifactPath = args.evidence_artifact_path.trim()
    const defectClass = args.defect_class.trim()

    if (!defectClass) {
      throw new Error("defect_class must not be empty.")
    }
    if (sourceTicket.status !== "done" && !["done", "superseded"].includes(sourceTicket.resolution_state)) {
      throw new Error(`Source ticket ${sourceTicket.id} must already be complete before issue intake can route post-completion work.`)
    }

    const evidenceArtifact = sourceTicket.artifacts.find((artifact) => artifact.path === evidenceArtifactPath)
    if (!evidenceArtifact) {
      throw new Error(`Source ticket ${sourceTicket.id} does not reference the evidence artifact ${evidenceArtifactPath}.`)
    }

    const outcome = resolveDefectOutcome(sourceTicket, {
      acceptance_broken: args.acceptance_broken,
      scope_changed: args.scope_changed,
      rollback_required: args.rollback_required,
    })

    let requiredNextAction = outcome
    let createdTicketId: string | null = null
    if (outcome === "invalidates_done") {
      markTicketReopened(sourceTicket, workflow, `Issue intake invalidated prior completion: ${defectClass}`)
      setPlanApprovedForTicket(workflow, sourceTicket.id, false)
      manifest.active_ticket = sourceTicket.id
      syncWorkflowSelection(workflow, manifest)
      requiredNextAction = "reopen_source_ticket"
    } else if (outcome === "follow_up" || outcome === "rollback_required") {
      const followUpDecisionBlockers = [...(args.follow_up_decision_blockers || [])]
      if (outcome === "rollback_required") {
        followUpDecisionBlockers.unshift("Rollback or containment work is required before normal forward progress.")
        sourceTicket.verification_state = "invalidated"
        getTicketWorkflowState(workflow, sourceTicket.id).needs_reverification = true
        markArtifactsHistorical(sourceTicket, undefined, "invalidated", `Rollback required after ${defectClass} issue intake.`)
      }
      const followUp = createTicketRecord({
        id: normalizeOptional(args.follow_up_id) || "",
        title: normalizeOptional(args.follow_up_title) || "",
        lane: normalizeOptional(args.follow_up_lane) || sourceTicket.lane,
        wave: typeof args.follow_up_wave === "number" ? args.follow_up_wave : sourceTicket.wave,
        summary: normalizeOptional(args.follow_up_summary) || "",
        acceptance: args.follow_up_acceptance || [],
        depends_on: args.follow_up_depends_on,
        decision_blockers: followUpDecisionBlockers,
        parallel_safe: args.follow_up_parallel_safe,
        overlap_risk: args.follow_up_overlap_risk,
        source_ticket_id: sourceTicket.id,
        source_mode: "post_completion_issue",
      })
      if (manifest.tickets.some((ticket) => ticket.id === followUp.id)) {
        throw new Error(`Ticket already exists: ${followUp.id}`)
      }
      if (followUp.depends_on.includes(sourceTicket.id)) {
        throw new Error(`Follow-up ticket ${followUp.id} cannot depend on its source ticket ${sourceTicket.id}; route that relationship through source/follow-up linkage instead.`)
      }
      for (const dependency of followUp.depends_on) {
        getTicket(manifest, dependency)
      }
      manifest.tickets.push(followUp)
      if (!sourceTicket.follow_up_ticket_ids.includes(followUp.id)) {
        sourceTicket.follow_up_ticket_ids.push(followUp.id)
      }
      setPlanApprovedForTicket(workflow, followUp.id, false)
      manifest.active_ticket = followUp.id
      syncWorkflowSelection(workflow, manifest)
      createdTicketId = followUp.id
      requiredNextAction = outcome === "rollback_required" ? "create_rollback_ticket" : "create_follow_up_ticket"
    }

    const priorCompletionTrusted = outcome === "no_action" || outcome === "follow_up"
    const artifactBody = renderArtifact({
      sourceTicketId: sourceTicket.id,
      defectClass,
      evidenceArtifactPath,
      outcome,
      priorCompletionTrusted,
      requiredNextAction,
    })
    const canonicalPath = normalizeRepoPath(defaultArtifactPath(sourceTicket.id, "review", "issue-discovery"))
    await writeText(canonicalPath, artifactBody)

    const registry = await loadArtifactRegistry()
    const issueArtifact = await registerArtifactSnapshot({
      ticket: sourceTicket,
      registry,
      source_path: canonicalPath,
      kind: "issue-discovery",
      stage: "review",
      summary: `${defectClass} intake routed to ${outcome}.`,
    })

    await saveWorkflowBundle({ workflow, manifest, registry })

    return JSON.stringify(
      {
        source_ticket_id: sourceTicket.id,
        outcome,
        issue_artifact: issueArtifact.path,
        prior_completion_trusted: priorCompletionTrusted,
        created_ticket_id: createdTicketId,
        active_ticket: manifest.active_ticket,
      },
      null,
      2,
    )
  },
})

